#!/bin/bash
# =============================================================================
# v2.6 Indicator Probes — V4 Pipeline (Train Only, Incremental)
# =============================================================================
#
# Training-only script for v2.6 indicators generated by probe.generate_v4.
# Meant to run while generation is still in progress for other indicators —
# trains probes for whichever indicator data files exist under probe/data/v4_v2_6.
#
# train.py skips indicators whose probes already exist (per-layer), so this
# script is safe to re-run as more generation completes.
#
# Usage:
#   bash scripts/probe_train_eval/run_v2_6_v4_train.sh [options]
#
# Options:
#   --label-mode MODE      turn or span (default: span)
#   --detect-layers L...   Layers to probe (default: "27 28 29 30")
#   --indicators "A" "B"   Train only these indicators (default: all .json files
#                          under probe/data/v4_v2_6/)
# =============================================================================

set -e

LABEL_MODE="span"
DETECT_LAYERS="27 29"
INDICATORS=()

while [[ $# -gt 0 ]]; do
    case $1 in
        --label-mode) LABEL_MODE="$2"; shift 2 ;;
        --detect-layers) DETECT_LAYERS="$2"; shift 2 ;;
        --indicators) shift
            while [[ $# -gt 0 && "$1" != --* ]]; do
                INDICATORS+=("$1"); shift
            done ;;
        *) echo "Unknown option: $1"; exit 1 ;;
    esac
done

# ---- Configuration ----
BASE_DIR=/workspace-vast/kaiwen/persona_vectors/data_generation
PYTHON=${BASE_DIR}/ood_misalignment_eval/deception-detection/.venv/bin/python

DATA_DIR=${BASE_DIR}/probe/data/v4_v2_6
PROBE_DIR=${BASE_DIR}/probe/probes/v4_v2_6_${LABEL_MODE}

REG_COEFF=10.0
PARTITION="general,overflow"
QOS="high"
TRAIN_MEM="128G"

# ---- Discover indicators ----
# Only include indicators whose generation has fully finished. Source of truth:
# "Saved to <path>" lines in the latest generate_v4 log — these are written
# only after all 3 steps (positives, hard negatives, benign OT) complete.
if [ ${#INDICATORS[@]} -eq 0 ]; then
    LATEST_LOG=$(ls -t ${BASE_DIR}/logs/generate_v4_*.log 2>/dev/null | head -1)
    if [ -z "${LATEST_LOG}" ]; then
        echo "ERROR: no generate_v4 log found under ${BASE_DIR}/logs/" >&2
        exit 1
    fi
    echo "Using log: ${LATEST_LOG}"
    # Files marked as "Saved to ..." across all v4 logs (handle restarts)
    FINISHED_FILES=$(grep -h "^  Saved to " ${BASE_DIR}/logs/generate_v4_*.log 2>/dev/null \
        | awk '{print $3}' | sort -u)
    if [ -z "${FINISHED_FILES}" ]; then
        echo "ERROR: no finished indicators found in generate_v4 logs" >&2
        exit 1
    fi
    for f in ${FINISHED_FILES}; do
        if [ -f "$f" ]; then
            name=$(${PYTHON} -c "import json,sys; print(json.load(open(sys.argv[1]))['indicator_name'])" "$f")
            INDICATORS+=("$name")
        fi
    done
fi

echo "Training ${#INDICATORS[@]} indicators:"
for ind in "${INDICATORS[@]}"; do echo "  - ${ind}"; done
echo ""

# ---- Split across 3 jobs ----
NUM=${#INDICATORS[@]}
SPLIT_SIZE=$(( (NUM + 2) / 3 ))
SPLIT_1=("${INDICATORS[@]:0:${SPLIT_SIZE}}")
SPLIT_2=("${INDICATORS[@]:${SPLIT_SIZE}:${SPLIT_SIZE}}")
SPLIT_3=("${INDICATORS[@]:$((SPLIT_SIZE * 2))}")

timestamp=$(date +%Y%m%d_%H%M%S)
WORK_DIR="${BASE_DIR}/logs/v2_6_v4_train_${timestamp}"
mkdir -p "${WORK_DIR}"

TRAIN_JOBS=()

for SPLIT_IDX in 1 2 3; do
    eval "SPLIT_INDS=(\"\${SPLIT_${SPLIT_IDX}[@]}\")"
    if [ ${#SPLIT_INDS[@]} -eq 0 ]; then continue; fi

    TRAIN_SCRIPT="${WORK_DIR}/train_split${SPLIT_IDX}.qsh"

    cat <<SLURM_HEADER > "${TRAIN_SCRIPT}"
#!/bin/bash
#SBATCH --job-name=probe_train_v26_s${SPLIT_IDX}
#SBATCH --output=${WORK_DIR}/train_split${SPLIT_IDX}_%j.out
#SBATCH --error=${WORK_DIR}/train_split${SPLIT_IDX}_%j.err
#SBATCH --gres=gpu:1
#SBATCH --partition=${PARTITION}
#SBATCH --qos=${QOS}
#SBATCH --mem=${TRAIN_MEM}
#SBATCH --chdir=${BASE_DIR}

source ${BASE_DIR}/ood_misalignment_eval/deception-detection/.venv/bin/activate
export HF_HOME=/workspace-vast/pretrained_ckpts
export HF_HUB_OFFLINE=1

echo "=========================================="
echo "Training v2.6 Probes — split ${SPLIT_IDX}/3"
echo "Label mode: ${LABEL_MODE}"
echo "Detect layers: ${DETECT_LAYERS}"
echo "Data dir:  ${DATA_DIR}"
echo "Probe dir: ${PROBE_DIR}"
echo "Started: \$(date)"
echo "=========================================="
SLURM_HEADER

    for ind in "${SPLIT_INDS[@]}"; do
        cat <<EOF >> "${TRAIN_SCRIPT}"

echo ""
echo "--- Training: ${ind} ---"
${PYTHON} -m probe.train \\
    --indicator-set v2_6 \\
    --indicator "${ind}" \\
    --label-mode "${LABEL_MODE}" \\
    --reg-coeff ${REG_COEFF} \\
    --detect-layers ${DETECT_LAYERS} \\
    --reasoning-only \\
    --threshold-mode sentence \\
    --val-fraction 0.2 \\
    --data-dir "${DATA_DIR}" \\
    --output-dir "${PROBE_DIR}"
EOF
    done

    cat <<EOF >> "${TRAIN_SCRIPT}"

echo ""
echo "Training split ${SPLIT_IDX} complete at \$(date)"
EOF

    TRAIN_JOB=$(sbatch --parsable "${TRAIN_SCRIPT}")
    TRAIN_JOBS+=("${TRAIN_JOB}")
    echo "[train] split ${SPLIT_IDX} job ${TRAIN_JOB} submitted (${#SPLIT_INDS[@]} indicators, 1 GPU)"
done

echo ""
echo "========================================"
echo "SLURM Jobs Submitted"
echo "========================================"
echo "  Indicator set: v2.6"
echo "  Indicators:    ${NUM}"
echo "  Label mode:    ${LABEL_MODE}"
echo "  Data dir:      ${DATA_DIR}"
echo "  Probe dir:     ${PROBE_DIR}"
echo ""
echo "Monitor:"
echo "  squeue -u $(whoami)"
echo "  tail -f ${WORK_DIR}/*.out"
echo "========================================"
